sys_script_include.script:
var TRACENowNumberPreserver = Class.create();

TRACENowNumberPreserver.prototype = {

    initialize: function() {
        this.cfg = new TRACENowConfig();
    },

    /**
     * Called from Business Rule (Before Insert).
     * Sets number field to source value before platform auto-number fires.
     */
    apply: function(current) {
        var isActive = gs.getSession().getClientData(this.cfg.SESSION_ACTIVE);
        if (isActive !== 'true') return;

        var sourceNumber = gs.getSession().getClientData(this.cfg.SESSION_NUMBER);
        if (!sourceNumber) return;

        if (current.isValidField('number')) {
            current.setValue('number', sourceNumber);
            gs.log('TRACENow NumberPreserver: Applied source number: ' + sourceNumber, 'TRACENow');
        }
    },

    type: 'TRACENowNumberPreserver'
};
